	];

	const duration = buildDurationDetail(card);
	if (duration) {
		items.push(new SessionDetailItem(
			"Duration",
			duration.description,
			"clock",
			duration.tooltip,
		));
	}

	if (card.startedAt) {
		items.push(new SessionDetailItem(
			"Started",
			formatShortTimestamp(card.startedAt),
			"history",
			card.startedAt,
		));
	}

	if (card.author) {
		items.push(new SessionDetailItem("Author", card.author, "person"));
