import * as vscode from "vscode";
import { EntireStatusState, EntireWorkspaceState } from "../workspaceProbe";

interface StatusBarInfo {
  iconName: string;
  title: string;
  description: string;
  backgroundColor?: vscode.ThemeColor;
}

const WARNING_BACKGROUND = new vscode.ThemeColor("statusBarItem.warningBackground");

const statusInfoMap: Record<EntireStatusState, StatusBarInfo> = {
  [EntireStatusState.ENABLED]: {
    iconName: "git-compare",
    title: "Enabled",
    description: "Entire is enabled for this repository.",
  },
  [EntireStatusState.CLI_MISSING]: {
    iconName: "warning",
    title: "Not Found",
    description: "The Entire CLI is not available in the extension host environment.",
    backgroundColor: WARNING_BACKGROUND,
  },
  [EntireStatusState.NOT_GIT_REPO]: {
    iconName: "repo",
    title: "Not a git repo",
    description: "Open a Git repository to use Entire features.",
  },
  [EntireStatusState.DISABLED]: {
    iconName: "circle-slash",
    title: "Not Enabled",
    description: "Entire is not enabled for this repository.",
  },
};

function getStatusBarInfo(workspaceState: EntireWorkspaceState): StatusBarInfo {
	if (workspaceState.state !== EntireStatusState.ENABLED) {
		return statusInfoMap[workspaceState.state];
	}

	const sessionCount = workspaceState.activeSessions.length;
	if (sessionCount > 1) {
		const activeCount = workspaceState.activeSessions.filter((session) => session.status === "ACTIVE").length;
		return {
			iconName: "layers",
			title: `${sessionCount} Sessions`,
			description: activeCount > 0
				? `Multiple Entire sessions are live in this workspace (${activeCount} active).`
				: "Multiple Entire sessions are live in this workspace.",
		};
	}

	if (sessionCount === 1) {
		const session = workspaceState.activeSessions[0];
		const agent = formatAgentName(session.agent);
		const stateLabel = session.status === "ACTIVE" ? "Active" : "Idle";

		return {
			iconName: session.status === "ACTIVE" ? "pulse" : "clock",
			title: agent ? `${stateLabel} · ${agent}` : stateLabel,
			description: session.status === "ACTIVE"
				? "Entire is actively tracking a session in this workspace."
				: "Entire is tracking an idle live session in this workspace.",
		};
	}

  return statusInfoMap[EntireStatusState.ENABLED];
}

function buildTooltip(statusInfo: StatusBarInfo, workspaceState: EntireWorkspaceState): vscode.MarkdownString {
  const tooltip = new vscode.MarkdownString(undefined, true);
  tooltip.isTrusted = false;
  tooltip.supportThemeIcons = true;

  tooltip.appendMarkdown(`**Entire**\n\n`);
  tooltip.appendMarkdown("**Status:** ");
  tooltip.appendText(statusInfo.title);
  tooltip.appendText("\n");
  tooltip.appendText(statusInfo.description);

  if (workspaceState.binary?.cliVersion) {
    tooltip.appendMarkdown("\n**CLI Version:** ");
    tooltip.appendText(workspaceState.binary.cliVersion);
  }

  const sessionCount = workspaceState.activeSessions.length;
  tooltip.appendMarkdown("\n\n**Sessions:** ");
  tooltip.appendText(String(sessionCount));

  if (sessionCount > 0) {
    for (const session of workspaceState.activeSessions.slice(0, 3)) {
      tooltip.appendMarkdown("\n- ");
      tooltip.appendText(describeSession(session));
    }

    if (sessionCount > 3) {
      tooltip.appendMarkdown("\n- ");
      tooltip.appendText(`${sessionCount - 3} more session(s)`);
    }
  }

  if (workspaceState.settings?.settingsPaths.length) {
    tooltip.appendMarkdown("\n\n**Settings Files:** ");
    tooltip.appendText(String(workspaceState.settings.settingsPaths.length));
  }

  if (workspaceState.warnings.length > 0) {
    tooltip.appendMarkdown("\n\n**Warnings**");
    for (const warning of workspaceState.warnings) {
      tooltip.appendMarkdown("\n- ");
      tooltip.appendText(warning);
    }
  }

  tooltip.appendMarkdown("\n\n_Click to show Entire status._");

  return tooltip;
}

function describeSession(session: EntireWorkspaceState["activeSessions"][number]): string {
	const parts: string[] = [];
	const agent = formatAgentName(session.agent);

	if (agent) {
		parts.push(agent);
	}
	if (session.model) {
		parts.push(session.model);
	}
	if (session.status) {
		parts.push(session.status);
	}
	if (session.sessionId) {
		parts.push(`#${session.sessionId.slice(0, 8)}`);
	}

  return parts.join(" · ");
}

function formatAgentName(agentType?: string): string | undefined {
  if (!agentType) {
    return undefined;
  }

  return agentType
    .split(/[-_]/g)
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

export function createStatusBarItem(command: string, workspaceState: EntireWorkspaceState): vscode.StatusBarItem {
  const statusBarItem = vscode.window.createStatusBarItem(
    "session.bridge.entire.status",
    vscode.StatusBarAlignment.Left,
    100,
  );
  updateStatusBarItem(statusBarItem, command, workspaceState);

  return statusBarItem;
}

export function updateStatusBarItem(
  statusBarItem: vscode.StatusBarItem,
  command: string,
  workspaceState: EntireWorkspaceState,
): void {
  const statusInfo = getStatusBarInfo(workspaceState);
  const label = `Session Bridge (Entire): ${statusInfo.title}`;

  statusBarItem.name = "Session Bridge Status";
  statusBarItem.text = `$(${statusInfo.iconName}) ${label}`;
  statusBarItem.tooltip = buildTooltip(statusInfo, workspaceState);
  statusBarItem.command = command;
  statusBarItem.backgroundColor = statusInfo.backgroundColor;
  statusBarItem.accessibilityInformation = {
    label,
    role: "button",
  };
}

import { NormalizedRewindPoint } from "./rewindIndex";
import type {
	CheckpointSummaryRecord,
	InitialAttribution,
	SessionContentRecord,
	SummaryRecord,
	TokenUsage,
} from "./types";

/** Normalized live-or-historical session status used by card and detail models. */
export type SessionStatus = "ACTIVE" | "IDLE" | "ENDED";

/** Per-file diff statistics aggregated from active-branch associated commits. */
export interface FileDiffStat {
	path: string;
	additions?: number;
	deletions?: number;
}

/** Rollup of changed-file counts and numeric line deltas for a checkpoint. */
export interface DiffSummaryModel {
	filesChanged: number;
	linesAdded?: number;
	linesRemoved?: number;
}

/** Commit metadata associated with a checkpoint on the active branch. */
export interface AssociatedCommitModel {
	sha: string;
	shortSha: string;
	message: string;
	body?: string;
	authorName: string;
	authorEmail?: string;
	authoredAt?: string;
	fileStats?: FileDiffStat[];
	patchText?: string;
}

/** Current rewindability and rewind-mode metadata for a checkpoint or temporary point. */
export interface RewindAvailability {
	isAvailable: boolean;
	pointId?: string;
	checkpointId?: string;
	isLogsOnly: boolean;
	isTaskCheckpoint: boolean;
	isTemporary: boolean;
	message?: string;
	sessionId?: string;
}

/** Normalized model for a session browser card. */
export interface SessionCheckpointEntry {
	checkpointId: string;
	sessionIndex: number;
	session: SessionContentRecord;
	checkpointTokenUsage?: TokenUsage;
}

/** Normalized model for a session browser card. */
export interface EntireSessionCard {
	id: string;
	sessionId: string;
	promptPreview: string;
	displayHash?: string;
	checkpointIds: string[];
	checkpointEntries?: SessionCheckpointEntry[];
	agent?: string;
	model?: string;
	status: SessionStatus;
	author?: string;
	branch?: string;
	createdAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	stepCount?: number;
	toolCount?: number;
	tokenCount?: number;
	attribution?: InitialAttribution;
	checkpointCount: number;
	latestCheckpointId?: string;
	latestAssociatedCommitSha?: string;
	isLiveOnly: boolean;
	searchText: string;
}

/** Normalized model for the live active-session tree view. */
export interface EntireActiveSessionCard {
	id: string;
	sessionId: string;
	status: SessionStatus;
	phase?: string;
	promptPreview: string;
	agent?: string;
	model?: string;
	startedAt?: string;
	lastInteractionAt?: string;
	durationMs?: number;
	checkpointCount: number;
	turnCount?: number;
	tokenCount?: number;
	attribution?: InitialAttribution;
	lastCheckpointId?: string;
	author?: string;
	worktreePath?: string;
	worktreeId?: string;
	baseCommit?: string;
	transcriptPath?: string;
	hasShadowBranch: boolean;
	isStuck: boolean;
	canRunDoctor: boolean;
	canOpenLastCheckpoint: boolean;
	canOpenTranscript: boolean;
	searchText: string;
}

export interface SessionDetailTarget {
	sessionId: string;
	promptPreview: string;
	source: "live" | "checkpoint";
	checkpointIds?: string[];
	checkpointEntries?: SessionCheckpointEntry[];
}

export interface SessionTranscriptTarget extends SessionDetailTarget {
	lastCheckpointId?: string;
	transcriptPath?: string;
}

export interface SessionDetailToolActivity {
	id: string;
	kind: "tool_use";
	label: string;
	detail?: string;
}

export interface SessionDetailAuxiliaryBlock {
	id: string;
	kind: "thinking" | "tool_use" | "output";
	label: string;
	detail?: string;
	tone?: "default" | "success" | "error";
	display?: "text" | "code";
}

export interface SessionDetailTurn {
	id: string;
	actor: {
		kind: "user" | "agent";
		name?: string;
		initials: string;
		imageUri?: string;
	};
	timestamp?: string;
	text?: string;
	toolActivities: SessionDetailToolActivity[];
	auxiliaryBlocks?: SessionDetailAuxiliaryBlock[];
}

export interface EntireSessionDetailModel {
	sessionId: string;
	source: "live" | "checkpoint";
	promptPreview: string;
	status: SessionStatus;
	startedAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	checkpointCount: number;
	turnCount?: number;
	toolCount?: number;
	tokenCount?: number;
	model?: string;
	attribution?: InitialAttribution;
	transcriptAvailable: boolean;
	turns: SessionDetailTurn[];
}

/** Normalized model for a checkpoint browser card. */
export interface EntireCheckpointCard {
	id: string;
	checkpointId?: string;
	rewindPointId?: string;
	promptPreview: string;
	displayHash: string;
	agent?: string;
	model?: string;
	status: SessionStatus;
	author?: string;
	timestamp?: string;
	branch?: string;
	tokenCount?: number;
	stepCount?: number;
	fileCount?: number;
	sessionCount: number;
	attribution?: InitialAttribution;
	summary?: SummaryRecord;
	primaryCommit?: AssociatedCommitModel;
	associatedCommitCount: number;
	diffSummary?: DiffSummaryModel;
	rewindAvailability?: RewindAvailability;
	isEphemeral: boolean;
	searchText: string;
}

/** A commit that has one or more checkpoints associated it it */
export interface CheckpointCommit {
	sha: string;
	shortSha: string;
	message: string;
	body?: string;
	authorName: string;
	authorEmail?: string;
	authoredAt?: string;
	fileStats?: FileDiffStat[];
	patchText?: string;
	checkpointIds: string[];
}

export interface ResolvedCheckpointRef {
	checkpointId: string;
	summary: CheckpointSummaryRecord | null;
	rewindPoints: NormalizedRewindPoint[];
}

export interface CommitCheckpointGroup {
	commit: CheckpointCommit;
	diffSummary?: DiffSummaryModel,
	checkpoints: ResolvedCheckpointRef[];
}

/** Groups checkpoint-linked commits under a shared authored day label for the tree view. */
export interface CheckpointDateGroup {
	timestamp: string;
	formattedDate: string;
	checkpointCommits: CommitCheckpointGroup[];
}

/** Lightweight model used to render the checkpoint tree without detail hydration. */
export interface CheckpointSummaryModel {
	id: string;
	checkpointId?: string;
	timestamp?: string;
	agent?: string;
	model?: string;
	author?: string;
	fileCount?: number;
	primaryCommit?: AssociatedCommitModel;
	diffSummary?: DiffSummaryModel;
	searchText: string;
}

/** Structured detail payload for a committed or temporary checkpoint item. */
export interface CheckpointDetailModel {
	id: string;
	checkpointId?: string;
	rewindPointId?: string;
	isEphemeral: boolean;
	title: string;
	promptPreview: string;
	hash: string;

