 13	
 14	const CONTEXT_SESSION = "session-bridge-session";
 15	const CONTEXT_DETAIL = "session-bridge-session-detail";
 16	const CONTEXT_ACTION = "session-bridge-session-action";
 17	const LOAD_TIMEOUT_MS = 50_000;
 18	
 19	export interface SessionsViewCommands {
 20		readonly refresh: string;
 21		readonly showStatus: string;
 22		readonly runDoctor: string;
 23		readonly openSessionTranscript: string;
 24	}
 25	
 26	export interface CheckpointSessionSelection {
 27		checkpointIds: string[];
 28		commitSha?: string;
 29	}
 30	
 31	export type SessionsTreeMode = "active" | "checkpoint";
 32	
 33	type SessionTreeCard = {
 34		kind: "live" | "checkpoint";
 35		sessionId: string;
 36		status: SessionStatus;
 37		phase?: string;
 38		promptPreview: string;
 39		agent?: string;
 40		model?: string;
 41		author?: string;
 42		startedAt?: string;
 43		lastActivityAt?: string;
 44		durationMs?: number;
 45		attribution?: InitialAttribution;
 46		checkpointCount: number;
 47		stepCount?: number;
 48		turnCount?: number;
 49		toolCount?: number;
 50		tokenCount?: number;
 51		checkpointIds?: string[];
 52		checkpointEntries?: SessionCheckpointEntry[];
 53		lastCheckpointId?: string;
 54		transcriptPath?: string;
 55		worktreePath?: string;
 56		worktreeId?: string;
 57		baseCommit?: string;
 58		hasShadowBranch: boolean;
 59		isStuck: boolean;
 60		canRunDoctor: boolean;
 61		canOpenLastCheckpoint: boolean;
 62		canOpenTranscript: boolean;
 63		searchText: string;
 64	};
 65	
 66	type LoadState =
 67		| { kind: "ready" }
 68		| { kind: "loading" }
 69		| { kind: "loaded"; cards: SessionTreeCard[] }
 70		| { kind: "error"; message: string };
 71	
 72	class EmptyStateItem extends vscode.TreeItem {
 73		constructor(label: string, icon: string, tooltip?: string) {
 74			super(label, vscode.TreeItemCollapsibleState.None);
 75			this.tooltip = tooltip;
 76			this.iconPath = new vscode.ThemeIcon(icon);
 77			this.contextValue = CONTEXT_DETAIL;
 78		}
 79	}
 80	
 81	class SessionDetailItem extends vscode.TreeItem {
 82		constructor(label: string, description: string, icon: string, tooltip?: string) {
 83			super(label, vscode.TreeItemCollapsibleState.None);
 84			this.description = description;
 85			this.tooltip = tooltip ?? `${label}: ${description}`;
 86			this.iconPath = new vscode.ThemeIcon(icon);
 87			this.contextValue = CONTEXT_DETAIL;
 88		}
 89	}
 90	
 91	class SessionActionItem extends vscode.TreeItem {
 92		constructor(
 93			label: string,
 94			icon: string,
 95			command: vscode.Command,
 96			description?: string,
 97		) {
 98			super(label, vscode.TreeItemCollapsibleState.None);
 99			this.description = description;
100			this.iconPath = new vscode.ThemeIcon(icon);
101			this.command = command;
102			this.contextValue = CONTEXT_ACTION;
103		}
104	}
105	
106	export class SessionsTreeItem extends vscode.TreeItem {
107		constructor(
108			public readonly card: SessionTreeCard,
109		) {
110			super(buildSessionIdentity(card), vscode.TreeItemCollapsibleState.Collapsed);
111			this.description = card.status;
112			this.tooltip = buildSessionTooltip(card);
113			this.iconPath = new vscode.ThemeIcon(selectSessionIcon(card));
114			this.contextValue = CONTEXT_SESSION;
115		}
116	}
117	
118	export function getSessionDetailTarget(element: vscode.TreeItem | undefined): SessionDetailTarget | undefined {
119		if (!(element instanceof SessionsTreeItem)) {
120			return undefined;
121		}
122	
123		return {
124			sessionId: element.card.sessionId,
125			promptPreview: element.card.promptPreview,
126			source: element.card.kind,
127			checkpointIds: element.card.checkpointIds,
128			checkpointEntries: element.card.checkpointEntries,
129		};
130	}
131	
132	export class SessionsTreeViewProvider implements vscode.TreeDataProvider<vscode.TreeItem> {
133		private readonly changeEmitter = new vscode.EventEmitter<void>();
134		readonly onDidChangeTreeData = this.changeEmitter.event;
135	
136		private workspaceState: EntireWorkspaceState;
137		private repoPath: string | undefined;
138		private selectedCheckpointSelection: CheckpointSessionSelection | undefined;
139		private loadState: LoadState;
140		private loadGeneration = 0;
141	
142		constructor(
143			workspaceState: EntireWorkspaceState,
144			repoPath: string | undefined,
145			private readonly commands: SessionsViewCommands,
146			private readonly mode: SessionsTreeMode,
147			private readonly outputChannel?: vscode.OutputChannel,
148			private readonly loadCheckpointSessions: (repoPath: string, checkpointIds: string[]) => Promise<EntireSessionCard[]> = listSessionsForCheckpointIds,
149		) {
150			this.workspaceState = workspaceState;
